/**
 * DeepLinkHandlerActivity - Entry point for all deep links with scheme "myapp://"
 * 
 * Add to AndroidManifest.xml:
 * 
 * <activity
 *     android:name=".DeepLinkHandlerActivity"
 *     android:exported="true"
 *     android:launchMode="singleTask">
 *     <intent-filter>
 *         <action android:name="android.intent.action.VIEW" />
 *         <category android:name="android.intent.category.DEFAULT" />
 *         <category android:name="android.intent.category.BROWSABLE" />
 *         <data android:scheme="myapp" />
 *     </intent-filter>
 * </activity>
 */
class DeepLinkHandlerActivity : Activity() {

    companion object {
        private const val TAG = "DeepLinkHandler"
        
        // Route constants
        const val ROUTE_PROFILE = "profile"
        const val ROUTE_PAYMENT = "payment"
        const val ROUTE_PROMO = "promo"
        const val ROUTE_PRODUCT = "product"
        
        // Extra keys
        const val EXTRA_USER_ID = "extra_user_id"
        const val EXTRA_PAYMENT_ACTION = "extra_payment_action"
        const val EXTRA_PAYMENT_TRANSACTION_ID = "extra_payment_transaction_id"
        const val EXTRA_PROMO_CODE = "extra_promo_code"
        const val EXTRA_PRODUCT_ID = "extra_product_id"
        const val EXTRA_DEEP_LINK_SOURCE = "extra_deep_link_source"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        handleDeepLink(intent)
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        intent?.let { handleDeepLink(it) }
    }

    private fun handleDeepLink(intent: Intent) {
        val uri = intent.data

        if (uri == null) {
            Log.w(TAG, "Deep link received with null URI")
            navigateToMain()
            return
        }

        Log.d(TAG, "Deep link received: $uri")

        val deepLinkResult = DeepLinkParser.parse(uri)
        
        when (deepLinkResult) {
            is DeepLinkResult.Profile -> navigateToProfile(deepLinkResult.userId, deepLinkResult.source)
            is DeepLinkResult.PaymentConfirm -> navigateToPaymentConfirm(deepLinkResult.transactionId, deepLinkResult.source)
            is DeepLinkResult.PaymentHistory -> navigateToPaymentHistory(deepLinkResult.source)
            is DeepLinkResult.Promo -> navigateToPromo(deepLinkResult.promoCode, deepLinkResult.source)
            is DeepLinkResult.Product -> navigateToProduct(deepLinkResult.productId, deepLinkResult.source)
            is DeepLinkResult.Main -> navigateToMain(deepLinkResult.source)
            is DeepLinkResult.Unknown -> {
                Log.w(TAG, "Unknown deep link: $uri")
                Toast.makeText(this, "Unknown link", Toast.LENGTH_SHORT).show()
                navigateToMain()
            }
        }
    }

    private fun navigateToProfile(userId: String, source: String?) {
        val intent = Intent(this, ProfileActivity::class.java).apply {
            putExtra(EXTRA_USER_ID, userId)
            source?.let { putExtra(EXTRA_DEEP_LINK_SOURCE, it) }
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        startActivity(intent)
        finish()
    }

    private fun navigateToPaymentConfirm(transactionId: String?, source: String?) {
        val intent = Intent(this, PaymentConfirmActivity::class.java).apply {
            putExtra(EXTRA_PAYMENT_ACTION, "confirm")
            transactionId?.let { putExtra(EXTRA_PAYMENT_TRANSACTION_ID, it) }
            source?.let { putExtra(EXTRA_DEEP_LINK_SOURCE, it) }
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        startActivity(intent)
        finish()
    }

    private fun navigateToPaymentHistory(source: String?) {
        val intent = Intent(this, PaymentHistoryActivity::class.java).apply {
            putExtra(EXTRA_PAYMENT_ACTION, "history")
            source?.let { putExtra(EXTRA_DEEP_LINK_SOURCE, it) }
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        startActivity(intent)
        finish()
    }

    private fun navigateToPromo(promoCode: String, source: String?) {
        val intent = Intent(this, PromoActivity::class.java).apply {
            putExtra(EXTRA_PROMO_CODE, promoCode)
            source?.let { putExtra(EXTRA_DEEP_LINK_SOURCE, it) }
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        startActivity(intent)
        finish()
    }

    private fun navigateToProduct(productId: String, source: String?) {
        val intent = Intent(this, ProductActivity::class.java).apply {
            putExtra(EXTRA_PRODUCT_ID, productId)
            source?.let { putExtra(EXTRA_DEEP_LINK_SOURCE, it) }
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        startActivity(intent)
        finish()
    }

    private fun navigateToMain(source: String? = null) {
        val intent = Intent(this, MainActivity::class.java).apply {
            source?.let { putExtra(EXTRA_DEEP_LINK_SOURCE, it) }
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        startActivity(intent)
        finish()
    }
}

/**
 * Sealed class representing all possible deep link destinations
 */
sealed class DeepLinkResult {
    abstract val source: String?

    data class Profile(val userId: String, override val source: String? = null) : DeepLinkResult()
    data class PaymentConfirm(val transactionId: String? = null, override val source: String? = null) : DeepLinkResult()
    data class PaymentHistory(override val source: String? = null) : DeepLinkResult()
    data class Promo(val promoCode: String, override val source: String? = null) : DeepLinkResult()
    data class Product(val productId: String, override val source: String? = null) : DeepLinkResult()
    data class Main(override val source: String? = null) : DeepLinkResult()
    data class Unknown(val uri: Uri, override val source: String? = null) : DeepLinkResult()
}

/**
 * Parser for deep link URIs
 * 
 * Supported formats:
 * - myapp://profile/{userId}?source=email
 * - myapp://payment/confirm?transaction_id=abc123&source=push
 * - myapp://payment/history
 * - myapp://promo/{promoCode}
 * - myapp://product/{productId}
 */
object DeepLinkParser {

    private const val TAG = "DeepLinkParser"

    fun parse(uri: Uri): DeepLinkResult {
        val scheme = uri.scheme
        if (scheme != "myapp") {
            Log.w(TAG, "Unexpected scheme: $scheme")
            return DeepLinkResult.Unknown(uri)
        }

        val host = uri.host ?: return DeepLinkResult.Unknown(uri)
        val pathSegments = uri.pathSegments
        val source = uri.getQueryParameter("source")

        Log.d(TAG, "Parsing - host: $host, pathSegments: $pathSegments, source: $source")

        return when (host) {
            DeepLinkHandlerActivity.ROUTE_PROFILE -> parseProfile(pathSegments, source, uri)
            DeepLinkHandlerActivity.ROUTE_PAYMENT -> parsePayment(pathSegments, source, uri)
            DeepLinkHandlerActivity.ROUTE_PROMO -> parsePromo(pathSegments, source, uri)
            DeepLinkHandlerActivity.ROUTE_PRODUCT -> parseProduct(pathSegments, source, uri)
            "home", "main" -> DeepLinkResult.Main(source)
            else -> DeepLinkResult.Unknown(uri, source)
        }
    }

    private fun parseProfile(pathSegments: List<String>, source: String?, uri: Uri): DeepLinkResult {
        val userId = pathSegments.firstOrNull()
        return if (userId != null && userId.isNotBlank()) {
            DeepLinkResult.Profile(userId, source)
        } else {
            Log.w(TAG, "Profile deep link missing userId: $uri")
            DeepLinkResult.Unknown(uri, source)
        }
    }

    private fun parsePayment(pathSegments: List<String>, source: String?, uri: Uri): DeepLinkResult {
        val action = pathSegments.firstOrNull()
        return when (action) {
            "confirm" -> {
                val transactionId = uri.getQueryParameter("transaction_id")
                DeepLinkResult.PaymentConfirm(transactionId, source)
            }
            "history" -> DeepLinkResult.PaymentHistory(source)
            else -> {
                Log.w(TAG, "Unknown payment action: $action")
                DeepLinkResult.Unknown(uri, source)
            }
        }
    }

    private fun parsePromo(pathSegments: List<String>, source: String?, uri: Uri): DeepLinkResult {
        val promoCode = pathSegments.firstOrNull()
        return if (promoCode != null && promoCode.isNotBlank()) {
            DeepLinkResult.Promo(promoCode, source)
        } else {
            Log.w(TAG, "Promo deep link missing promo code: $uri")
            DeepLinkResult.Unknown(uri, source)
        }
    }

    private fun parseProduct(pathSegments: List<String>, source: String?, uri: Uri): DeepLinkResult {
        val productId = pathSegments.firstOrNull()
        return if (productId != null && productId.isNotBlank()) {
            DeepLinkResult.Product(productId, source)
        } else {
            Log.w(TAG, "Product deep link missing product ID: $uri")
            DeepLinkResult.Unknown(uri, source)
        }
    }
}

